import React from "react"
import Select from 'react-select'
//import Calendar from 'react-select-date'
import { Calendar, DateObject } from "react-multi-date-picker"
import { properties } from '../../properties/properties.js'
import Moment from 'moment'
import {Tab, Tabs, TabList, TabPanel} from 'react-tabs'
import 'react-tabs/style/react-tabs.css'
import FullCalendar from '@fullcalendar/react' // must go before plugins
import dayGridPlugin from '@fullcalendar/daygrid' // a plugin!
import interactionPlugin from "@fullcalendar/interaction" // needed for dayClick
import listPlugin from '@fullcalendar/list'
import timeGridPlugin from '@fullcalendar/timegrid'
import $ from 'jquery'
import 'bootstrap'


class Room extends React.Component {

    constructor(props) {
        super(props);
        this.state = {
            screen: 0, selectedDate: "", availableRooms: [], showRoom: false, selectedRoom: {}, showTime: false, events: [], availableEvents: [], showConfirm: false, selectedStart: "", selectedEnd: "", showAvailableSelect: false
        };
    }


    handleCancelBooking = () => {
        this.setState({showConfirm: false})
    }

    handleBooking = () => {

        var events = this.state.events


        var startTime = Moment(this.state.selectedDate).format("YYYY-MM-DD") + "T" + Moment(this.state.selectedStart).format("HH:mm:ss")
        var endTime = Moment(this.state.selectedDate).format("YYYY-MM-DD") + "T" + Moment(this.state.selectedEnd).format("HH:mm:ss")


        events.push({title: this.state.selectedRoom.label + ': Keith Siu', start: startTime, end: endTime})

        //console.log(events)

        this.setState({events: events})
        this.setState({showConfirm: false})
    }


    handleAvailableSelect = (selectionInfo) => {
        console.log(selectionInfo)





    }



    handleSelect = (selectionInfo) => {
        console.log(selectionInfo)



        var eventsFilter = this.state.events.filter(Record => Moment(Record.start).format("YYYY-MM-DD") === Moment(this.state.selectedDate).format("YYYY-MM-DD"))

        console.log(eventsFilter)

        var foundOverlap = false

        var startTime = Moment(Moment(this.state.selectedDate).format("YYYY-MM-DD") + "T" + Moment(String(selectionInfo.start)).format("HH:mm:ss"))
        var endTime = Moment(Moment(this.state.selectedDate).format("YYYY-MM-DD") + "T" + Moment(String(selectionInfo.end)).format("HH:mm:ss"))


        for(var index in eventsFilter) {
            var eventStartTime = Moment(eventsFilter[index].start)
            var eventEndTime = Moment(eventsFilter[index].end)
            if (startTime >= eventStartTime && startTime < eventEndTime) {
                foundOverlap = true
            }
            if (endTime > eventStartTime && endTime <= eventEndTime) {
                foundOverlap = true
            }
            if (eventStartTime >= startTime && eventStartTime < endTime) {
                foundOverlap = true
            }
            if (eventEndTime > startTime && eventEndTime <= endTime) {
                foundOverlap = true
            }
        }


        if (!foundOverlap) {
            this.setState({showConfirm: true})
            this.setState({selectedStart: String(selectionInfo.start)})
            this.setState({selectedEnd: String(selectionInfo.end)})
        } else {
            alert("The selected time has been occupied")
            this.setState({showConfirm: false})
        }


    }


    handleCheckTime = () => {
        if (JSON.stringify(this.state.selectedRoom).length > 2) {
            this.setState({showRoom: false})
            this.setState({showTime: true})
            this.setState({showConfirm: false})



            var events =  [
                {
                    id: 2,
                    title: this.state.selectedRoom.label + ": Keith Siu",
                    start: '2021-12-15T13:00:00',
                    end: '2021-12-15T15:00:00'
                }
            ]
            this.setState({events: events})



        } else {
            alert("please select room(s)")
        }
    }

    handleRoomSelect = (selectedOptions) => {
        //console.log(selectedOptions)
        this.setState({selectedRoom: selectedOptions})
    }


    handleFindRoom = () => {

        //console.log(this.state.selectedDate)

        if (this.state.selectedDate.length > 0) {
            var rooms = []
            rooms.push({value: 'FOCUS5501', label: 'FOCUS 5501'})
            rooms.push({value: 'FOCUS5502', label: 'FOCUS 5502'})
            rooms.push({value: 'FOCUS5503', label: 'FOCUS 5503'})
            rooms.push({value: 'FOCUS5403', label: 'FOCUS 5403'})
            rooms.push({value: 'FOCUS5405', label: 'FOCUS 5405'})
            rooms.push({value: 'FOCUS5615', label: 'FOCUS 5615'})
            rooms.push({value: 'FOCUS5331', label: 'FOCUS 5331'})

            rooms.push({value: 'HUDDLE5402', label: 'HUDDLE 5402'})
            rooms.push({value: 'HUDDLE5104', label: 'HUDDLE 5104'})
            rooms.push({value: 'HUDDLE5221', label: 'HUDDLE 5221'})

            this.setState({availableRooms: rooms})
            this.setState({showRoom: true})
            this.setState({showTime: false})
            this.setState({showConfirm: false})
            this.setState({selectedRoom: {}})
        } else {
            alert("Please select a date to find room")
        }
    }


    handleDateChange = (date) => {



        this.setState({selectedDate: new DateObject(date).format()})

        this.setState({showConfirm: false})
        this.setState({showRoom: false})
        this.setState({showTime: false})

        /*
        if (this.state.selectedDate !== date) {
          this.setState({selectedDate: date})
          //console.log(date);var myDate = new Date(date);console.log(myDate);
        }
        */

        var rooms = []
        rooms.push({value: 'FOCUS5501', label: 'FOCUS 5501'})
        rooms.push({value: 'FOCUS5502', label: 'FOCUS 5502'})
        rooms.push({value: 'FOCUS5503', label: 'FOCUS 5503'})
        rooms.push({value: 'FOCUS5403', label: 'FOCUS 5403'})
        rooms.push({value: 'FOCUS5405', label: 'FOCUS 5405'})
        rooms.push({value: 'FOCUS5615', label: 'FOCUS 5615'})
        rooms.push({value: 'FOCUS5331', label: 'FOCUS 5331'})

        rooms.push({value: 'HUDDLE5402', label: 'HUDDLE 5402'})
        rooms.push({value: 'HUDDLE5104', label: 'HUDDLE 5104'})
        rooms.push({value: 'HUDDLE5221', label: 'HUDDLE 5221'})

        this.setState({availableRooms: rooms})
        this.setState({showRoom: true})
        this.setState({showTime: false})
        this.setState({showConfirm: false})
        this.setState({selectedRoom: {}})


      }


        componentDidMount() {


            this.setState({screen: 1})
            this.setState({showAvailableSelect: false})



            var availableEvents = []



          }

          render() {


            var header = "Loading ..."




            if (this.state.screen === 1) {









              header = ""
              var content = []
              var rightContent = []
              var leftContent = []



              /*
              const options = [
                {value: '5930', label: 'Khanna, Raman'},
                {value: '1837', label: 'Sharpe, Bradley'},
                {value: '1850', label: 'Wu, Ethel'},
                {value: '3135', label: 'Shoeb, Marwa'},
                {value: '2470', label: 'Schaeffer, Sarah'},
                {value: '1889', label: 'Najafi, Nader'},
                {value: '6276', label: 'Lai, Andy'},
                {value: '6548', label: 'Auerbach, Andrew'}
              ]
*/


              /*
              const groupedOptions = [
                {label: 'M-L Wards', options: options},
                {label: 'Rounding, Goldman Medicine', options: goldmanOptions}
              ]
              */



              if (this.state.showRoom) {
                rightContent.push(<div style={{marginTop: "50px"}}>Available Room:</div>)

                rightContent.push(<div style={{marginTop: "5px", display: "block"}}><Select
                    value={this.state.selectedRoom}
                    isMulti={false}
                    name="availableRoomSelect"
                    options={this.state.availableRooms}
                    className="basic-multi-select"
                    classNamePrefix="select"
                    onChange={this.handleRoomSelect}
                    /></div>)

                    var buttonText = "check available time"
                    rightContent.push(<div style={{textAlign: "right", marginTop: "15px"}}><button onClick={() => this.handleCheckTime()}  id="sendPage" style={{height: "40px", width: "200px", fontSize: "16px", backgroundColor: "yellow" }}>{buttonText}</button></div>)

              }





              if (this.state.showTime) {


                rightContent.push(<div style={{color:"red", marginBottom: "10px"}}>*** please select the time below for reservation ***</div>)
                rightContent.push(<div>Room: {this.state.selectedRoom.label}</div>)

                if (this.state.showConfirm) {

                    var tempContent = []

                    tempContent.push(<div>Reservation for: {this.state.selectedDate}<hr></hr></div>)
                    tempContent.push(<div style={{marginBottom:"5px"}}>Room: {this.state.selectedRoom.label}</div>)



                    tempContent.push(<div style={{marginBottom:"5px"}}>Start: {Moment(this.state.selectedStart).format("hh:mm A")}</div>)
                    tempContent.push(<div style={{marginBottom:"5px"}}>End: {Moment(this.state.selectedEnd).format("hh:mm A")}</div>)


                    tempContent.push(<div style={{marginTop: "15px"}}><button onClick={() => this.handleCancelBooking()}  id="cancelBooking" style={{height: "30px", width: "120px", fontSize: "16px", backgroundColor: "yellow" }}>Cancel</button>&nbsp;&nbsp;<button onClick={() => this.handleBooking()}  id="booking" style={{height: "30px", width: "120px", fontSize: "16px", backgroundColor: "green" }}>Confirm</button></div>)


                    rightContent.push(<div style={{marginTop: "20px", marginBottom: "20px", borderStyle:"solid",height:"150px",width:"800px",borderColor:"coral",padding:"10px"}}>{tempContent}</div>)
                    window.scrollTo(0, 0)
                }




                rightContent.push( <FullCalendar
                    plugins={[interactionPlugin, timeGridPlugin ]}
                    initialView="timeGridDay"
                    slotMinTime="06:00:00"
                    slotMaxTime="18:00:00"
                    height="670px"
                    allDaySlot={false}
                    initialDate={new Date(this.state.selectedDate)}
                    headerToolbar={{right: ""}}
                    selectable={true}
                    events={this.state.events}
                    select={e => this.handleSelect(e)}
                    //selectOverlap={function(event) {return event.rendering === 'background'}}

                    //eventClick={this.handleEventClick}
                    //dateClick={this.handleDateClick}
                    //eventOrder="id"
                    //eventDidMount={this.handleDidMount}
                    //initialDate= {this.state.setCalendarDate}
                    //eventsSet={this.handleEvents}
                    //navLinkDayClick={this.handleLinkClick}

                  />)



              }




              leftContent.push(<div>select a date</div>)

              /*
              leftContent.push(<div style={{marginTop: "15px", display: "block"}}><Calendar
              onSelect={(date) => {this.handleDateChange(date);}}
              selectDateType="multiple"
              slotInfo={false}
              showDateInputField={false}
              //onSelect={this.handleDateChange}
              /></div>)
              */
              leftContent.push(<div style={{marginTop: "15px", display: "block"}}><Calendar 
              //value={["10/01/2021","10/02/2021"]}
              //onChange={this.handleDateChange}
              value={this.state.selectedDate}
              onChange={dateValue => {this.handleDateChange(dateValue)}}

              format="MM/DD/YYYY"
              numberOfMonths={1}

            /></div>)
              //leftContent.push(<div style={{marginTop: "15px"}}><button onClick={() => this.handleFindRoom()}  id="findRoom" style={{height: "40px", width: "120px", fontSize: "16px", backgroundColor: "yellow" }}>Find Room</button></div>)


              //content.push(<div style={{display: "flex"}}><div style={{marginRight: "50px", width: "400px"}}>{leftContent}</div><div style={{flex: "100%"}}>{rightContent}</div></div>)


              //this.state.savedPage



              var manageSpace = []

              if (this.state.showAvailableSelect) {

                var tempContent = []

                tempContent.push(<div>Available for: {this.state.selectedDate}<hr></hr></div>)


                tempContent.push(<div style={{marginBottom:"5px"}}>Start: {Moment(this.state.selectedStart).format("hh:mm A")}</div>)
                tempContent.push(<div style={{marginBottom:"5px"}}>End: {Moment(this.state.selectedEnd).format("hh:mm A")}</div>)


                tempContent.push(<div style={{marginTop: "15px"}}><button onClick={() => this.handleCancelBooking()}  id="cancelBooking" style={{height: "30px", width: "120px", fontSize: "16px", backgroundColor: "yellow" }}>Cancel</button>&nbsp;&nbsp;<button onClick={() => this.handleBooking()}  id="booking" style={{height: "30px", width: "120px", fontSize: "16px", backgroundColor: "green" }}>Confirm</button></div>)


                rightContent.push(<div style={{marginTop: "20px", marginBottom: "20px", borderStyle:"solid",height:"150px",width:"800px",borderColor:"coral",padding:"10px"}}>{tempContent}</div>)
                window.scrollTo(0, 0)

              }



              manageSpace.push(<div style={{color:"red", marginBottom: "10px"}}>*** please select available time below for other to book your space ***</div>)
              manageSpace.push( <FullCalendar
                plugins={[interactionPlugin, timeGridPlugin ]}
                initialView="timeGridWeek"
                slotMinTime="06:00:00"
                slotMaxTime="18:00:00"
                height="670px"
                allDaySlot={false}
                //initialDate={new Date(this.state.selectedDate)}
                //headerToolbar={{right: ""}}
                selectable={true}
                events={this.state.availableEvents}
                select={e => this.handleAvailableSelect(e)}
                //selectOverlap={function(event) {return event.rendering === 'background'}}

                //eventClick={this.handleEventClick}
                //dateClick={this.handleDateClick}
                //eventOrder="id"
                //eventDidMount={this.handleDidMount}
                //initialDate= {this.state.setCalendarDate}
                //eventsSet={this.handleEvents}
                //navLinkDayClick={this.handleLinkClick}

              />)




              var tabContent = []


              tabContent.push(<Tabs>
                  <TabList>
                      <Tab>Your Reservation</Tab>
                      <Tab>Find Available Space</Tab>
                      <Tab>Manage Your Space</Tab>
                  </TabList>
                  <TabPanel>
                        <h2>Your Reservation</h2>
                  </TabPanel>
                  <TabPanel>
                      <h2>Find Available Space</h2>
                      <div style={{display: "flex"}}><div style={{marginRight: "50px", width: "400px"}}>{leftContent}</div><div style={{flex: "100%"}}>{rightContent}</div></div>
                  </TabPanel>
                  <TabPanel>
                      <h2>Manager Your Space</h2>
                      <div >{manageSpace}</div>



                  </TabPanel>

              </Tabs>)

            content.push(tabContent)




          }



            return (




<div style={{minHeight: "500px", marginLeft: "50px", marginRight: "50px"}}><h2 className="display-4 text-center">{header}</h2>{content}

</div>

            );
          }


  };

  export default Room
